parameters.jsonBody:
={
  "query": "query GetTranscript($id: String!) { transcript(id: $id) { id title date duration participants transcript_url summary { keywords overview action_items } } }",
  "variables": {
    "id": "{{ $json.meetingId }}"
  }
}

parameters.jsCode:
const response = $input.first().json;
const config = $('2. Set — Config Values').item.json;

const t = response?.data?.transcript;
if (!t || !t.id) throw new Error('Transcript not found for meetingId: ' + config.meetingId);

const summary = t.summary || {};
const keywords = (summary.keywords || []).slice(0, 12).join(', ') || 'None';
const overview = (summary.overview || '').substring(0, 600);
const actionItems = (summary.action_items || []).slice(0, 5).join(' | ') || 'None';

const meetingDate = t.date
  ? new Date(t.date).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' })
  : new Date().toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });

return [{
  json: {
    meetingId: t.id,
    title: t.title || 'Untitled Meeting',
    meetingDate,
    durationMin: Math.round((t.duration || 0) / 60),
    participants: (t.participants || []).join(', ') || 'Unknown',
    transcriptUrl: t.transcript_url || 'Not available',
    keywords,
    overview,
    actionItems,
    loggedAt: new Date().toISOString().replace('T', ' ').substring(0, 16),
    sheetId: config.sheetId,
    sheetName: config.sheetName
  }
}];

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "category": {
      "type": "string",
      "description": "Exactly one of: Sales, Client, Internal, HR, Product, Finance, Other"
    },
    "confidence": {
      "type": "string",
      "description": "Exactly one of: High, Medium, Low"
    },
    "reason": {
      "type": "string",
      "description": "One sentence under 20 words explaining the category choice"
    }
  },
  "required": ["category", "confidence", "reason"]
}

parameters.jsCode:
const aiOutput = $input.first().json.output;
const meetingData = $('4. Code — Extract Meeting Data').item.json;

const category = aiOutput?.category || 'Other';
const confidence = aiOutput?.confidence || 'Low';
const reason = aiOutput?.reason || 'Could not determine category';

const categoryEmoji = {
  'Sales': '💰',
  'Client': '🤝',
  'Internal': '🏢',
  'HR': '👥',
  'Product': '🛠️',
  'Finance': '📊',
  'Other': '📋'
};

const confidenceEmoji = {
  'High': '✅',
  'Medium': '🟡',
  'Low': '⚠️'
};

return [{
  json: {
    meetingDate: meetingData.meetingDate,
    title: meetingData.title,
    category: (categoryEmoji[category] || '📋') + ' ' + category,
    confidence: (confidenceEmoji[confidence] || '🟡') + ' ' + confidence,
    reason,
    durationMin: meetingData.durationMin,
    participants: meetingData.participants,
    keywords: meetingData.keywords,
    transcriptUrl: meetingData.transcriptUrl,
    loggedAt: meetingData.loggedAt,
    sheetId: meetingData.sheetId,
    sheetName: meetingData.sheetName
  }
}];
